          int32_t rdi_1 = arg3 - rax_3;      // UNDERFLOW: if bLength > buffer_size, wraps to ~0xFFFFFF00
          if (rdi_1 >= 2) {                  // unsigned compare: 0xFFFFFF00 >= 2 → TRUE (bypassed!)
              // ... enters descriptor parsing loop with corrupted bounds ...
              void* rbx_2 = &r12[*r12];      // pointer advanced by bLength past buffer start
              char rcx_10 = *rbx_2;          // OOB READ: reads bLength of next descriptor past buffer
              // ... loop continues reading OOB memory ...
          }
      }
  }

